    createGrid() {
        if (!this.scene) return;

        // 创建网格组
        this.grid = new THREE.Group();
        this.grid.position.y = 0; // 确保在 y=0 平面
        this.grid.name = 'CustomGrid';

        // 创建基础网格（灰白色，不包含中心线）
        // 通过设置相同的颜色来隐藏 GridHelper 的中心线
        const grayColor = 0xaaaaaa;
        this.gridBase = new THREE.GridHelper(2000, 2000, grayColor, grayColor);

        // 设置透明度
        if (Array.isArray(this.gridBase.material)) {
            this.gridBase.material.forEach((mat: THREE.Material) => {
                (mat as THREE.LineBasicMaterial).opacity = 0.5;
                (mat as THREE.LineBasicMaterial).transparent = true;
            });
        } else {
            (this.gridBase.material as THREE.LineBasicMaterial).opacity = 0.5;
            (this.gridBase.material as THREE.LineBasicMaterial).transparent = true;
        }

        this.grid.add(this.gridBase);

        this.scene.add(this.grid);

        // 初始化密度
        this.currentGridDensity = 1;
        this.grid.visible = globalConfig.sceneParams.grid; // 初始化网格可见性
    }

