    // 设置渲染模式 需要对接Core中的渲染模式 - 0-普通，1-法线，2-深度；点云暂时不支持，后续增加 - by helen
    setRenderMode(mode: number) {
        this.currentRenderMode = mode;
        const isHeatmap = mode === globalConfig.renderMode.heatmap;
        // this.ensureHeatmapPanel();
        // this.setHeatmapPanelVisible(isHeatmap);

        if (isHeatmap) {
            // Heatmap is an overlay mode; keep base rendering in normal mode.
            this.disableHeatmapPipeline();
            if (this.gaussianThreeJSRenderer) {
                this.objects.forEach(obj => {
                    if (obj.type === 'visionary') {
                        const modelIndex = this.findGaussianModelIndex(obj.object.uuid);
                        if (modelIndex >= 0) {
                            this.gaussianThreeJSRenderer.setModelRenderMode(`model_${modelIndex}`, globalConfig.renderMode.normal);
                        }
                    }
                });
            }
            this.updateHeatmapPipeline();
            return;
        }

        // Leaving heatmap mode: hard-disable extra passes and hide UI.
        this.disableHeatmapPipeline();

        if (this.gaussianThreeJSRenderer) {
            this.objects.forEach(obj => {
                if (obj.type === 'visionary') {
                    const modelIndex = this.findGaussianModelIndex(obj.object.uuid);
                    if (modelIndex >= 0) {
                        this.gaussianThreeJSRenderer.setModelRenderMode(`model_${modelIndex}`, mode);
                    }
                }
            });
        }
    }
