    ////////////////////  object参数更新  //////////////////////////////////////////////////
    // 更新对象参数
    updateObjectParams(id: string, params: { position: { x: number, y: number, z: number }, rotation: { x: number, y: number, z: number }, scale: { x: number, y: number, z: number }, gaussianParams: any | null, cameraParams: any | null }) {
        let obj = this.objects.find(obj => obj.id == id);
        if (obj) {
            obj.object.position.set(params.position.x, params.position.y, params.position.z);
            obj.object.rotation.set(params.rotation.x, params.rotation.y, params.rotation.z);
            obj.object.scale.set(params.scale.x, params.scale.y, params.scale.z);

            // ✅ 同步 RecordingCamera 的相机位置
            this.syncRecordingCameraIfNeeded(obj, 'updateObjectParams');

            if (params.gaussianParams) {
                if (this.gaussianThreeJSRenderer) {
                    const modelIndex = this.findGaussianModelIndex(id);
                    if (modelIndex >= 0) {
                        const modelId = `model_${modelIndex}`;
                        console.log('设置模型高斯参数-----modelId', modelId, params.gaussianParams);
                        // this.gaussianThreeJSRenderer.setModelVisible(modelId, params.gaussianParams.visible);
                        this.gaussianThreeJSRenderer.setModelGaussianScale(modelId, params.gaussianParams.gaussianScale);
                        this.gaussianThreeJSRenderer.setModelOpacityScale(modelId, params.gaussianParams.opacityScale);
                        this.gaussianThreeJSRenderer.setModelMaxShDeg(modelId, params.gaussianParams.maxShDeg);
                        this.gaussianThreeJSRenderer.setModelTimeScale(modelId, params.gaussianParams.timeScale);
                        this.gaussianThreeJSRenderer.setModelTimeOffset(modelId, params.gaussianParams.timeOffset);
                        // this.gaussianThreeJSRenderer.setModelMaxPiexl(modelId, params.gaussianParams.maxPiexl);
                    }
                }
            }

            if (params.cameraParams && obj.type === 'recordingCamera') {
                obj.object.userData.recordingCamera.camera.fov = params.cameraParams.fov;
                obj.object.userData.recordingCamera.camera.near = params.cameraParams.near;
                obj.object.userData.recordingCamera.camera.far = params.cameraParams.far;
                obj.object.userData.recordingCamera.camera.aspect = params.cameraParams.aspect;
                obj.object.userData.recordingCamera.camera.updateProjectionMatrix();
                obj.object.userData.recordingCamera.camera.updateMatrixWorld();
                (modelUtils as any).onRecordingCameraChange(obj); // 如果录制相机，同步其他场景的录制预览相机参数
            }
        }
        this.updateBoundingBox(id);
    }

