    /////////////////////   获取/设置 模型高斯参数      /////////////////////////////////////////////////////
    /**
     * 通过 VisionaryObject 的 ID (UUID) 查找对应的 GaussianModel 在 gaussianModels 数组中的索引
     * @param visionaryObjectId VisionaryObject 的 ID (UUID)
     * @returns 模型在数组中的索引，如果找不到返回 -1
     */
    private findGaussianModelIndex(visionaryObjectId: string): number {
        if (!this.gaussianThreeJSRenderer) return -1;

        const obj = this.getObjectById(visionaryObjectId);
        if (!obj || obj.type !== 'visionary') return -1;

        // 通过 getGaussianModels 获取模型数组
        const gaussianModels = this.gaussianThreeJSRenderer.getGaussianModels();

        // 查找匹配的模型（通过 UUID 或对象引用）
        const index = gaussianModels.findIndex((model: any) => {
            // 比较 UUID 或对象引用
            return model.uuid === obj.object.uuid || model === obj.object;
        });

        if (index === -1) {
            console.warn(`[VisionaryScene] GaussianModel not found for VisionaryObject ID: ${visionaryObjectId}`);
        }

        return index;
    }

    private findGaussianModelIndexByObject(obj: VisionaryObject): number {
        if (!this.gaussianThreeJSRenderer) return -1;
        const gaussianModels = this.gaussianThreeJSRenderer.getGaussianModels();
        const index = gaussianModels.findIndex((model: any) => {
            return model.uuid === obj.object.uuid || model === obj.object;
        });
        return index;
    }

    /**
     * 
     * @param id 获取模型高斯参数
     * @returns 
     */
    getModelGaussianParams(id: string) {
        console.log('根据uuid获取模型高斯参数', id);
        let obj = this.objects.find(obj => obj.id == id);
        if (obj) {
            if (obj.type === 'visionary') { // 只有高斯模型才有高斯参数
                if (this.gaussianThreeJSRenderer) {
                    const modelIndex = this.findGaussianModelIndex(id);
                    if (modelIndex >= 0) {
                        const allParams = this.gaussianThreeJSRenderer.getModelParams();
                        if (allParams.models[`model_${modelIndex}`]) {
                            console.log('获取模型高斯参数', allParams.models[`model_${modelIndex}`]);
                            return allParams.models[`model_${modelIndex}`];
                        }
                    }
                }
            } else {
                return null;
            }
        } else {
            console.log('获取模型高斯参数失败，对象不存在', id);
        }
        return null;
    }
    // 获取录制相机参数 - 用于关键帧记录及动画渲染
    getRecordingCameraParams(id: string) {
        let obj = this.objects.find(obj => obj.id == id);
        if (obj) {
            if (obj.type === 'recordingCamera') { // 只有渲染相机才有渲染相机参数
                console.log('获取渲染相机参数', obj);
                return {
                    fov: obj.object.userData.recordingCamera.camera.fov,
                    near: obj.object.userData.recordingCamera.camera.near,
                    far: obj.object.userData.recordingCamera.camera.far,
                    aspect: obj.object.userData.recordingCamera.camera.aspect,
                };
            } else {
                return null;
            }
        } else {
            console.log('获取渲染相机参数失败，对象不存在', id);
        }
        return null;
    }
    // 设置模型可见性
    setModelVisible(id: string, visible: boolean) {
        let obj = this.objects.find(obj => obj.id == id);
        if (obj) {
            if (obj.type === 'visionary') {
                if (this.gaussianThreeJSRenderer) {
                    const modelIndex = this.findGaussianModelIndex(id);
                    if (modelIndex >= 0) {
                        this.gaussianThreeJSRenderer.setModelVisible(`model_${modelIndex}`, visible);
                    }
                }
            } else {
                obj.object.visible = visible;
                this.updateBoundingBox(id);
            }
        }
    }

