    public async loadHeatmapCodebookFile(file: File): Promise<void> {
        let codebook: Float32Array | null = null;
        const filename = file.name.toLowerCase();

        if (filename.endsWith('.txt') || filename.endsWith('.csv')) {
            const text = await file.text();
            const tokens = text
                .split(/[\s,]+/)
                .map((token) => token.trim())
                .filter((token) => token.length > 0);
            const values = tokens.map((token) => Number(token));
            if (values.some((value) => Number.isNaN(value))) {
                throw new Error('Codebook txt contains invalid number');
            }
            codebook = new Float32Array(values);
        } else {
            const buffer = await file.arrayBuffer();
            codebook = new Float32Array(buffer);
        }

        const rows = 64;
        const cols = 512;
        if (!codebook || codebook.length !== rows * cols) {
            throw new Error(`Codebook length mismatch: ${codebook?.length ?? 0} != ${rows * cols}`);
        }

        this.languageCodebook = codebook;
        this.weightGram64x64 = this.computeGramMatrix(this.languageCodebook);
        this.weightQuery64 = null;
        this.weightQueryLoaded = false;
        this.updateHeatmapQuery64(true);
        this.refreshHeatmapQueryDropdown();
        this.updateHeatmapPipeline();
    }

    public async loadHeatmapQueryListFile(file: File): Promise<void> {
        const text = await file.text();
        this.loadHeatmapQueryListFromText(text);
    }

    public loadHeatmapQueryListFromText(text: string): void {
        const json = JSON.parse(text);
        const queries = json?.queries;
        if (!Array.isArray(queries) || queries.length === 0) {
            throw new Error('Query list JSON has no queries');
        }
        const normalizedQueries: Array<{ name: string; vector: number[] }> = [];
        for (const item of queries) {
            const name = item?.name;
            const vector = item?.vector;
            if (typeof name !== 'string' || !Array.isArray(vector) || vector.length !== 512) {
                throw new Error('Query list item is invalid');
            }
            normalizedQueries.push({ name, vector });
        }
        this.languageQueries = normalizedQueries;
        if (!this.heatmapQueryName || !normalizedQueries.some((item) => item.name === this.heatmapQueryName)) {
            this.heatmapQueryName = normalizedQueries[0]?.name ?? null;
        }
        this.weightQuery64 = null;
        this.weightQueryLoaded = false;
        this.refreshHeatmapQueryDropdown();
        this.updateHeatmapQuery64(true);
        this.updateHeatmapPipeline();
    }

