    public getGaussianRenderer(): any {
        return this.gaussianThreeJSRenderer;
    }

    // 重置场景
    public async resetScene(isCloseLoading: boolean = true) {
        console.log('reset场景', this.objects);
        modelDialogTools.showLoadingInfoModal(getI18nText('loadingMessage.resettingScene'));
        // 1. 停止动画、关闭录制相机预览窗口
        this.stopAnimation();

        // 2. 清理当前选中
        this.clearCurrentSelected(); // 清空当前选中
        // 4. 清理对象
        this.clearObjects();
        // 5. 清理高斯模型
        this.clearGaussianRenderer();

        // 6. 触发自定义回调
        if (this.objectChangeCallback && typeof this.objectChangeCallback === 'function') {
            this.objectChangeCallback();
        }
        if (this.sceneResetCallback && typeof this.sceneResetCallback === 'function') {
            this.sceneResetCallback();
        }

        console.log('reset Scene', this.objects);
        this.isLoopAnimation = true;
        this.animate();
        modelDialogTools.showLoadingInfoModal(getI18nText('loadingMessage.sceneResetComplete'));
        if (isCloseLoading) {
            modelDialogTools.closeLoadingInfoModal(1);
        }
    }

    // 4. 清理所有对象
    clearObjects() {
        if (this.scene) {
            this.objects.forEach((obj) => {
                this.scene!.remove(obj.object);
                // 如果有高斯渲染器，清理高斯模型
                if (obj.type === 'visionary' && this.gaussianThreeJSRenderer) {
                    const modelIndex = this.findGaussianModelIndex(obj.id);
                    if (modelIndex >= 0) {
                        try {
                            this.detachProxyForGaussian(obj.object as GaussianModel);
                            // 尝试从高斯渲染器中移除模型
                            if (this.gaussianThreeJSRenderer.removeModelById) {
                                this.gaussianThreeJSRenderer.removeModelById(`model_${modelIndex}`);
                            }
                        } catch (error) {
                            console.warn('移除高斯模型失败:', error);
                        }
                    }
                }
            });
        }
        this.objects = [];
        if (this.gaussianProxyMap) {
            this.gaussianProxyMap.clear();
        }
        if (this.selectables) {
            this.selectables = [];
        }
        // 清除当前选中的对象和gizmo target
        this.currentSelectedObjectId = null;
        this.gizmoManager?.setTarget(null);
    }

    // 6. 清理高斯渲染器  isDestroy: 是否销毁Gizmo管理器,如果只是清理场景，不需要销毁Gizmo管理器
    clearGaussianRenderer(isDestroy: boolean = false) {
        if (this.gizmoManager) {
            try {
                this.gizmoManager.setTarget(null);
            } catch (error) {
                console.warn('清理Gizmo管理器失败:', error);
            }
            if (isDestroy) {
                this.gizmoManager.dispose();
            }
        }

        if (this.gaussianThreeJSRenderer) {
            try {
                if (this.gaussianThreeJSRenderer.dispose) {
                    this.gaussianThreeJSRenderer.dispose();
                }
            } catch (error) {
                console.warn('清理高斯渲染器失败:', error);
            }
            this.gaussianThreeJSRenderer = null;
            console.log('清理高斯渲染器成功');
        }
    }
    /**
     * 销毁场景并释放所有资源
     */
    public destroy(): void {
        console.log('destroying scene:', this.id);

        // 1. 停止动画循环
        this.stopAnimation();

        // 2. 清理当前选中
        let currentSelected = globalManager.getCurrentSelected();
        console.log('currentSelected', currentSelected, this.id);
        if (currentSelected) {
            globalManager.setCurrentSelected(currentSelected.sceneid, '');
        }
        // 3. 清除所有渲染前/渲染后回调
        this.preRenderCallbacks = [];
        this.postRenderCallbacks = [];

        // 4. 移除窗口大小变化监听器
        window.removeEventListener('resize', this.resizeHandler);
        window.removeEventListener('event.modelSelectChange', this.modelSelectChangeHandler);

        // 6. 清理所有对象
        this.clearObjects();

        // 7. 清理高斯渲染器
        this.clearGaussianRenderer(true);

        // 8. 清理渲染器
        if (this.renderer) {
            try {
                // 移除 DOM 元素
                if (this.renderer.domElement && this.renderer.domElement.parentNode) {
                    this.renderer.domElement.parentNode.removeChild(this.renderer.domElement);
                }
                // WebGPURenderer 可能没有 dispose 方法
                if (typeof (this.renderer as any).dispose === 'function') {
                    (this.renderer as any).dispose();
                }
            } catch (error) {
                console.warn('清理渲染器失败:', error);
            }
            this.renderer = null;
        }

        // 9. 清理场景
        if (this.scene) {
            // 移除场景中的所有对象
            while (this.scene.children.length > 0) {
                this.scene.remove(this.scene.children[0]);
            }
            this.scene = null;
        }

        // 10. 清理相机
        this.camera = null;

        // 11. 清理网格
        this.grid = null;
        this.gridBase = null;

        // 12. 清理回调函数
        this.objectChangeCallback = null;

        // 13. 触发自定义销毁事件
        const customEvent = new CustomEvent('vinSceneDestroy', {
            detail: { sceneid: this.id }
        });
        window.dispatchEvent(customEvent);

        console.log('scene destroyed:', this.id);
    }
